import{_ as e}from"./chunks/system-diagram.Cz3-4A3B.js";import{_ as o,c as a,o as r,a5 as s}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"The Power of Simplicity","titleTemplate":"NpgsqlRest","description":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country.","frontmatter":{"layout":"doc","outline":[2,3],"title":"The Power of Simplicity","titleTemplate":"NpgsqlRest","description":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country.","badge":"human","head":[["meta",{"name":"keywords","content":"postgresql, npgsqlrest, software architecture, simplicity, data access pattern, orm, rest api, energy efficiency, database first"}],["meta",{"property":"og:title","content":"The Power of Simplicity"}],["meta",{"property":"og:description","content":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country."}],["meta",{"property":"og:type","content":"article"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"The Power of Simplicity"}]]},"headers":[],"relativePath":"blog/the-power-of-simplicity.md","filePath":"blog/the-power-of-simplicity.md"}'),n={name:"blog/the-power-of-simplicity.md"};function i(l,t,c,p,g,h){return r(),a("div",null,t[0]||(t[0]=[s('<h1 id="the-power-of-simplicity" tabindex="-1">The Power of Simplicity <a class="header-anchor" href="#the-power-of-simplicity" aria-label="Permalink to &quot;The Power of Simplicity&quot;">​</a></h1><p class="blog-meta"><span>March 2026</span> · <span class="tag">Architecture</span><span class="tag">Opinion</span></p><hr><p>The standard data access pattern for modern, business, data-driven applications is this:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>Service Layer</strong> → <strong>Repository</strong> → <strong>ORM</strong> → <strong>SQL</strong> (Automatic with ORM) → <strong>RDBMS</strong></p></blockquote><p>We do this so that we can mock the Repository and test logic in the Service. The problem with this approach is that once you realize how trivial it is to wire up database-aware tests - you can call them what you like, integration tests, database tests, whatever - once you realize that, you also realize you can collapse at least two layers:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>ORM</strong> → <strong>SQL</strong> (Automatic with ORM) → <strong>RDBMS</strong></p></blockquote><p>This is much, much simpler. But then, as you become proficient with SQL and you realize you can do things that ORM can&#39;t generate, and in many cases faster and more efficient, you realize this can be even simpler:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>SQL</strong> → <strong>RDBMS</strong></p></blockquote><p>And then you realize SQL actually has a rich type system - at least something mature and advanced as PostgreSQL does - and that type system can be used as a contract, and that Controller code is just boring glue code that can and should be automated:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Automatic Server Endpoint</strong> (Controller) → <strong>SQL</strong> → <strong>RDBMS</strong></p></blockquote><p>But why stop there? If the controller can be automated, why not generate those Fetch calls as well? And that SQL can be stored in the RDBMS. Finally, this is what we have, basically:</p><blockquote><p><strong>UI</strong> → <strong>RDBMS</strong></p></blockquote><p><img src="'+e+'" alt="System Diagram"></p><p>Now, if we all start doing software architecture like that, imagine how many tokens and energy we could save... That is what I call the energy efficiency. In a time of looming energy crisis, we could probably power a small country with the power of simplicity.</p><hr><p>If you want to learn how to do this with PostgreSQL, check out the <a href="/guide/quick-start.html">Quick Start Guide</a> or dive into the <a href="/blog/">Tutorials</a>.</p>',17)]))}const y=o(n,[["render",i]]);export{u as __pageData,y as default};
